class Solution:
    def bowlSubarrays(self, nums):
        n = len(nums)
        count = 0
        for l in range(n):
            for r in range(l + 2, n):
                inner_max = max(nums[l + 1:r])
                if min(nums[l], nums[r]) > inner_max:
                    count += 1
        return count

